{"operation": "write", "path": "/home/user/user_management.py", "content": "class User:
    """Represents a single user with validation logic."""

    def __init__(self, user_id: int, name: str, email: str, age: int):
        self.id = user_id
        self.name = name
        self.email = email
        self.age = age

    # --- Validation (static methods) ---

    @staticmethod
    def validate_email(email: str) -> bool:
        return '@' in email and '.' in email.split('@')[1]

    @staticmethod
    def validate_age(age: int) -> bool:
        return isinstance(age, int) and 0 < age < 150

    # --- Instance methods ---

    def update(self, name: str | None = None, email: str | None = None, age: int | None = None) -> "User":
        if name is not None:
            self.name = name
        if email is not None:
            self.email = email
        if age is not None:
            self.age = age
        return self

    def to_dict(self) -> dict:
        return {"id": self.id, "name": self.name, "email": self.email, "age": self.age}

    def __repr__(self) -> str:
        return f"User(id={self.id}, name='{self.name}', email='{self.email}', age={self.age})"


class UserRepository:
    """Manages a collection of User objects."""

    def __init__(self):
        self._users: list[User] = []
        self._next_id = 1

    def create(self, name: str, email: str, age: int) -> User:
        user = User(user_id=self._next_id, name=name, email=email, age=age)
        self._next_id += 1
        self._users.append(user)
        return user

    def update(self, user_id: int, name: str | None = None, email: str | None = None, age: int | None = None) -> User | None:
        user = self.get(user_id)
        if user is not None:
            user.update(name=name, email=email, age=age)
        return user

    def delete(self, user_id: int) -> None:
        self._users = [u for u in self._users if u.id != user_id]

    def get(self, user_id: int) -> User | None:
        for user in self._users:
            if user.id == user_id:
                return user
        return None

    def all(self) -> list[User]:
        return list(self._users)

    def __len__(self) -> int:
        return len(self._users)"}
